import React, {type FC} from "react";
import {Skeleton} from "primereact/skeleton";

export interface SkeletonRowsProps {
  rowsLength: number;
  isTable?: boolean;
}

const SkeletonRows: FC<SkeletonRowsProps> = ({
  rowsLength,
  isTable = false,
}) => {
  return (
    <>
      {Array.from(Array(rowsLength).keys()).map((key) => (
        <Skeleton
          key={key}
          height={"51px"}
          className="mb-2"
          borderRadius="10px"
        ></Skeleton>
      ))}
    </>
  );
};
export default SkeletonRows;
